import{c as e,O as i,i as r,m as t}from"./chunks/framework.BWIk71Uc.js";const m=JSON.parse('{"title":"Backend Learning Path","description":"A structured backend learning roadmap covering Java fundamentals, databases, Spring ecosystem, distributed systems, and DevOps practices.","frontmatter":{"title":"Backend Learning Path","description":"A structured backend learning roadmap covering Java fundamentals, databases, Spring ecosystem, distributed systems, and DevOps practices.","date":"2026-05-29T00:00:00.000Z","tags":["Java","MySQL","Redis","Spring","Docker","Linux"],"category":"knowledge","status":"draft","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"en/roadmap/backend.md","filePath":"en/roadmap/backend.md","lastUpdated":1780128182000}'),n={name:"en/roadmap/backend.md"};function l(s,a,o,d,c,p){return i(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1780012800000"},[...a[0]||(a[0]=[t('<h1 id="backend-learning-path" tabindex="-1">Backend Learning Path <a class="header-anchor" href="#backend-learning-path" aria-label="Permalink to “Backend Learning Path”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>This page organizes the key topics, learning order, and related notes for backend development. It provides a structured path from Java fundamentals to microservices architecture and project practice.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to “Learning Path”">​</a></h2><ul><li>Step 1: Master Java fundamentals and object-oriented programming</li><li>Step 2: Learn database basics and Spring Boot development</li><li>Step 3: Understand microservices architecture and components</li><li>Step 4: Practice with real projects and prepare for interviews</li></ul><h2 id="phase-1-java-fundamentals" tabindex="-1">Phase 1: Java Fundamentals <a class="header-anchor" href="#phase-1-java-fundamentals" aria-label="Permalink to “Phase 1: Java Fundamentals”">​</a></h2><ul><li>Java Basic Syntax</li><li>Object-Oriented Programming</li><li>Collection Framework</li><li>Exception Handling</li><li>I/O Streams</li><li>Multithreading</li><li>JVM Basics</li></ul><h2 id="phase-2-databases-and-tools" tabindex="-1">Phase 2: Databases and Tools <a class="header-anchor" href="#phase-2-databases-and-tools" aria-label="Permalink to “Phase 2: Databases and Tools”">​</a></h2><ul><li>MySQL Basics</li><li>MySQL Indexes and Transactions</li><li>Redis Basics</li><li>Git</li><li>Common Linux Commands</li></ul><h2 id="phase-3-spring-boot" tabindex="-1">Phase 3: Spring Boot <a class="header-anchor" href="#phase-3-spring-boot" aria-label="Permalink to “Phase 3: Spring Boot”">​</a></h2><ul><li>Web Development</li><li>Parameter Validation</li><li>Unified Response</li><li>Unified Exception Handling</li><li>Logging</li><li>API Documentation</li><li>Authentication and Authorization</li></ul><h2 id="phase-4-microservices" tabindex="-1">Phase 4: Microservices <a class="header-anchor" href="#phase-4-microservices" aria-label="Permalink to “Phase 4: Microservices”">​</a></h2><ul><li>Spring Cloud</li><li>Nacos</li><li>OpenFeign</li><li>Gateway</li><li>Sentinel</li><li>Seata</li><li>RabbitMQ</li><li>Docker Deployment</li></ul><h2 id="phase-5-project-practice" tabindex="-1">Phase 5: Project Practice <a class="header-anchor" href="#phase-5-project-practice" aria-label="Permalink to “Phase 5: Project Practice”">​</a></h2><ul><li>Read Open Source Projects</li><li>Analyze Project Architecture</li><li>Perform Secondary Development</li><li>Write Project Documentation</li><li>Prepare Interview Presentations</li></ul><h2 id="work-in-progress" tabindex="-1">Work in Progress <a class="header-anchor" href="#work-in-progress" aria-label="Permalink to “Work in Progress”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Work in Progress</p><p>This page is still being improved. More project-based examples and troubleshooting notes will be added later.</p></div>',17)])])}const u=e(n,[["render",l]]);export{m as __pageData,u as default};
